import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"How Prova works","description":"Three roles, one cryptographic contract.","frontmatter":{"description":"Three roles, one cryptographic contract."},"headers":[],"relativePath":"concepts/architecture.md","filePath":"concepts/architecture.md","lastUpdated":1777130260000}'),s={name:"concepts/architecture.md"};function i(n,e,l,h,d,p){return a(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="how-prova-works" tabindex="-1">How Prova works <a class="header-anchor" href="#how-prova-works" aria-label="Permalink to &quot;How Prova works&quot;">​</a></h1><p>Prova is built around <strong>three roles</strong> and a single on-chain contract that mediates between them.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   ┌────────┐         ┌────────┐         ┌──────────┐</span></span>
<span class="line"><span>   │ Client │ ◄─────► │ Prover │ ◄─────► │ Ethereum │</span></span>
<span class="line"><span>   └────────┘         └────────┘         └──────────┘</span></span>
<span class="line"><span>   stores · pays      stakes · stores    verifies · slashes</span></span>
<span class="line"><span>   verifies           proves             pays</span></span></code></pre></div><h2 id="the-roles" tabindex="-1">The roles <a class="header-anchor" href="#the-roles" aria-label="Permalink to &quot;The roles&quot;">​</a></h2><h3 id="client" tabindex="-1">Client <a class="header-anchor" href="#client" aria-label="Permalink to &quot;Client&quot;">​</a></h3><p>You. Or your app. Anyone who wants a file stored with cryptographic guarantees.</p><p>A client:</p><ul><li>Computes a <code>piece-cid</code> from their file (a content-addressed identifier)</li><li>Pays the storage fee in USDC</li><li>Verifies the file is still retrievable, whenever they want</li></ul><h3 id="prover" tabindex="-1">Prover <a class="header-anchor" href="#prover" aria-label="Permalink to &quot;Prover&quot;">​</a></h3><p>A node operator with disk and bandwidth. Provers earn USDC by storing client files and proving they still hold them.</p><p>A prover:</p><ul><li>Stakes USDC against the durability of what they hold</li><li>Stores files addressed by <code>piece-cid</code></li><li>Posts a cryptographic proof every 30 seconds (continuous PDP)</li><li>Gets slashed if they miss a proof</li></ul><h3 id="ethereum-base-l2" tabindex="-1">Ethereum (Base L2) <a class="header-anchor" href="#ethereum-base-l2" aria-label="Permalink to &quot;Ethereum (Base L2)&quot;">​</a></h3><p>The judge. Holds the storage marketplace contract, the prover registry, and the staking contract.</p><p>Ethereum:</p><ul><li>Records every deal proposal</li><li>Releases payment to the prover as proofs land</li><li>Slashes the prover&#39;s stake if a proof is missed</li><li>Is the only source of truth for who owes whom what</li></ul><h2 id="the-deal" tabindex="-1">The deal <a class="header-anchor" href="#the-deal" aria-label="Permalink to &quot;The deal&quot;">​</a></h2><p>A <strong>deal</strong> is the contract between a client and a prover for a single piece, for a fixed duration. Deals move through five states:</p><p><code>Proposed → Downloading → Storing → Active → Settled</code></p><p>You can read more in <a href="./deal-lifecycle">Deal lifecycle</a>.</p><h2 id="what-s-intentionally-not-in-prova" tabindex="-1">What&#39;s intentionally not in Prova <a class="header-anchor" href="#what-s-intentionally-not-in-prova" aria-label="Permalink to &quot;What&#39;s intentionally not in Prova&quot;">​</a></h2><ul><li><strong>No new chain.</strong> Prova lives on Base. Settlement is Ethereum-grade.</li><li><strong>No bridges.</strong> Payments are native USDC. No wrapped anything.</li><li><strong>No sealed PoRep.</strong> No TEEs. No fancy crypto theater. Just PDP — a 25-year-old, well-understood proof scheme.</li><li><strong>No custody.</strong> Provers can&#39;t see your data unless you give them retrieval rights. They prove they&#39;re storing the bytes; they don&#39;t necessarily know what the bytes mean.</li><li><strong>No token launch.</strong> No ICO, no airdrop, no governance theater. The unit of payment is USDC.</li></ul><h2 id="why-this-works" tabindex="-1">Why this works <a class="header-anchor" href="#why-this-works" aria-label="Permalink to &quot;Why this works&quot;">​</a></h2><p>A prover&#39;s incentive structure is simple:</p><table tabindex="0"><thead><tr><th>Action</th><th>Outcome</th></tr></thead><tbody><tr><td>Post a proof on time</td><td>Earn 99% of the deal&#39;s per-block payment</td></tr><tr><td>Miss a proof</td><td>Get slashed; deal is re-pinned to a healthy prover</td></tr><tr><td>Try to delete the file</td><td>Next proof fails; get slashed</td></tr><tr><td>Try to lie in the proof</td><td>Cryptographically impossible</td></tr></tbody></table><p>The math is in <a href="./continuous-proof">Continuous proof of storage</a>.</p><h2 id="pieces-not-files" tabindex="-1">Pieces, not files <a class="header-anchor" href="#pieces-not-files" aria-label="Permalink to &quot;Pieces, not files&quot;">​</a></h2><p>Prova stores <strong>pieces</strong>, not files. A piece is a content-addressed blob. If your file is bigger than the per-piece limit, you split it client-side and store each piece independently. (The CLI and SDK handle this for you.)</p><p>Two clients who upload the same file get the same <code>piece-cid</code>. The prover only stores one copy. The two clients each get their own deal.</p><h2 id="where-the-bytes-live" tabindex="-1">Where the bytes live <a class="header-anchor" href="#where-the-bytes-live" aria-label="Permalink to &quot;Where the bytes live&quot;">​</a></h2><p>For each piece-cid, multiple provers may hold a copy. This is <strong>redundancy</strong> — the <a href="./resilience">resilience model</a>. When you retrieve, the network routes you to the fastest healthy prover. If they&#39;re down, retrieval falls through to the next one.</p>`,31)])])}const y=t(s,[["render",i]]);export{u as __pageData,y as default};
